// Calculate price change % from last poll using workflow static data
const currentPrice = Number($input.first().json.price || 0);
const staticData = $getWorkflowStaticData('global');

const lastPrice = staticData.lastBtcPrice || currentPrice;
const lastTimestamp = staticData.lastBtcTimestamp || Date.now();

const changePercent = lastPrice > 0 ? ((currentPrice - lastPrice) / lastPrice) * 100 : 0;
const direction = changePercent > 0 ? 'UP' : changePercent < 0 ? 'DOWN' : 'FLAT';
const timeDeltaSec = (Date.now() - lastTimestamp) / 1000;

// Store current price for next poll
staticData.lastBtcPrice = currentPrice;
staticData.lastBtcTimestamp = Date.now();

// Track rolling 5-minute momentum (store last 5 prices)
if (!staticData.priceHistory) staticData.priceHistory = [];
staticData.priceHistory.push({ price: currentPrice, time: Date.now() });
// Keep only last 10 minutes of data
const tenMinAgo = Date.now() - (10 * 60 * 1000);
staticData.priceHistory = staticData.priceHistory.filter(p => p.time > tenMinAgo);

// Calculate 5-minute momentum
const fiveMinAgo = Date.now() - (5 * 60 * 1000);
const fiveMinPrices = staticData.priceHistory.filter(p => p.time <= fiveMinAgo);
const fiveMinPrice = fiveMinPrices.length > 0 ? fiveMinPrices[fiveMinPrices.length - 1].price : currentPrice;
const fiveMinChange = fiveMinPrice > 0 ? ((currentPrice - fiveMinPrice) / fiveMinPrice) * 100 : 0;
const fiveMinDirection = fiveMinChange > 0 ? 'UP' : fiveMinChange < 0 ? 'DOWN' : 'FLAT';

return [{
  json: {
    btcPrice: currentPrice,
    lastPrice,
    changePercent: changePercent.toFixed(4),
    direction,
    fiveMinChange: fiveMinChange.toFixed(4),
    fiveMinDirection,
    timeDeltaSec: timeDeltaSec.toFixed(0)
  }
}];

// Find the BTC short-term market and extract token IDs
const markets = $input.all();
const momentum = $('Calculate Momentum').first().json;

if (markets.length === 0) {
  return [{ json: { _noMatch: true } }];
}

// Look for 5-minute or short-term BTC markets
let bestMarket = null;
for (const item of markets) {
  const m = item.json;
  const q = (m.question || '').toLowerCase();
  // Prefer short-duration markets
  if (q.includes('5 min') || q.includes('5-min') || q.includes('15 min') || q.includes('15-min') || q.includes('next')) {
    bestMarket = m;
    break;
  }
}

// Fallback to first BTC market if no short-term found
if (!bestMarket) bestMarket = markets[0].json;

let clobTokenIds = bestMarket.clobTokenIds || [];
if (typeof clobTokenIds === 'string') {
  try { clobTokenIds = JSON.parse(clobTokenIds); } catch(e) { clobTokenIds = []; }
}

let outcomes = bestMarket.outcomes || [];
if (typeof outcomes === 'string') {
  try { outcomes = JSON.parse(outcomes); } catch(e) { outcomes = []; }
}

let outcomePrices = bestMarket.outcomePrices || [];
if (typeof outcomePrices === 'string') {
  try { outcomePrices = JSON.parse(outcomePrices); } catch(e) { outcomePrices = []; }
}

// YES token is typically index 0
const yesTokenId = clobTokenIds[0] || '';
const noTokenId = clobTokenIds[1] || '';

return [{
  json: {
    question: bestMarket.question || 'Unknown',
    conditionId: bestMarket.conditionId || '',
    slug: bestMarket.slug || '',
    yesTokenId,
    noTokenId,
    outcomes,
    outcomePrices,
    btcPrice: momentum.btcPrice,
    changePercent: momentum.changePercent,
    direction: momentum.direction,
    fiveMinChange: momentum.fiveMinChange,
    fiveMinDirection: momentum.fiveMinDirection,
    _noMatch: false
  }
}];

// Compare exchange momentum vs Polymarket pricing, detect edge
const priceData = $input.first().json;
const marketData = $('Find BTC Short-Term Market').first().json;

const polyPrice = Number(priceData.price || priceData.midpoint || 0);
const fiveMinChange = Number(marketData.fiveMinChange || 0);
const direction = marketData.fiveMinDirection;

// If exchange is moving UP, Polymarket YES should be higher
// If exchange is moving DOWN, Polymarket YES should be lower
// Edge = how much Polymarket lags the exchange signal
let impliedPolyDirection = polyPrice > 0.5 ? 'UP' : 'DOWN';
let edgePercent = 0;

if (direction === 'UP' && polyPrice < 0.5) {
  // Exchange says up, Polymarket says no -- potential edge
  edgePercent = Math.abs(fiveMinChange);
} else if (direction === 'DOWN' && polyPrice > 0.5) {
  // Exchange says down, Polymarket says yes -- potential edge
  edgePercent = Math.abs(fiveMinChange);
} else {
  // Aligned, no edge
  edgePercent = 0;
}

const hasEdge = edgePercent > 1.0; // 1% threshold

return [{
  json: {
    btcPrice: marketData.btcPrice,
    fiveMinChange,
    exchangeDirection: direction,
    polyPrice: polyPrice.toFixed(3),
    impliedPolyDirection,
    edgePercent: edgePercent.toFixed(2),
    hasEdge,
    question: marketData.question,
    slug: marketData.slug,
    spread: priceData.spread || 'N/A'
  }
}];

